import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { clearAuth } from '../api';
import { Menu, X, Home, MessageSquare, AlertTriangle, Bell, Users, LogOut } from 'lucide-react';

const navItems = [
  { name: 'Home',      path: '/user/home',      icon: Home },
  { name: 'Feedback',  path: '/user/feedback',  icon: MessageSquare },
  { name: 'Complaint', path: '/user/complaint', icon: AlertTriangle },
  { name: 'Notices',   path: '/user/notices',   icon: Bell },
  { name: 'Societies', path: '/user/societies', icon: Users },
];

const Navbar = () => {
  const location  = useLocation();
  const navigate  = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  const handleLogout = () => {
    clearAuth();
    navigate('/login');
  };

  return (
    <>
      <style>{`
        .nm-nav { display:flex; justify-content:space-between; align-items:center;
          padding:0 32px; height:64px; background:rgba(8,14,26,0.92);
          backdrop-filter:blur(16px); border-bottom:1px solid var(--border);
          position:sticky; top:0; z-index:1000; }
        .nm-logo { display:flex; align-items:center; gap:10px; cursor:pointer; }
        .nm-logo-icon { font-size:22px; color:var(--gold); }
        .nm-logo-text { font-family:var(--font-display); font-size:19px; font-weight:700;
          color:var(--gold); letter-spacing:0.02em; }
        .nm-links { display:flex; align-items:center; gap:4px; }
        .nm-link { display:flex; align-items:center; gap:7px; padding:8px 14px;
          border-radius:8px; font-size:14px; font-weight:500; color:var(--text-secondary);
          transition:all 0.2s; cursor:pointer; }
        .nm-link:hover  { background:var(--gold-dim); color:var(--text-primary); }
        .nm-link.active { background:var(--gold-dim); color:var(--gold); border:1px solid var(--border-accent); }
        .nm-link svg { width:15px; height:15px; }
        .nm-logout { display:flex; align-items:center; gap:7px; padding:8px 16px;
          background:rgba(239,68,68,0.1); border:1px solid rgba(239,68,68,0.25);
          color:#f87171; border-radius:8px; font-size:14px; font-weight:500;
          cursor:pointer; transition:all 0.2s; margin-left:8px; }
        .nm-logout:hover { background:rgba(239,68,68,0.2); color:#fca5a5; }
        .nm-hamburger { display:none; cursor:pointer; color:var(--gold); }
        .nm-mobile { display:none; flex-direction:column; padding:12px 24px 20px;
          background:var(--bg-secondary); border-bottom:1px solid var(--border); gap:4px; }
        .nm-mobile.open { display:flex; }
        .nm-mobile .nm-link { width:100%; }
        @media(max-width:900px) {
          .nm-links { display:none; }
          .nm-hamburger { display:block; }
        }
      `}</style>
      <nav className="nm-nav">
        <div className="nm-logo" onClick={() => navigate('/user/home')}>
          <span className="nm-logo-icon">⬡</span>
          <span className="nm-logo-text">HostelMate</span>
        </div>
        <div className="nm-links">
          {navItems.map(({ name, path, icon: Icon }) => (
            <Link key={path} to={path}
              className={`nm-link${location.pathname === path ? ' active' : ''}`}>
              <Icon /> {name}
            </Link>
          ))}
          <button className="nm-logout" onClick={handleLogout}><LogOut size={14} /> Logout</button>
        </div>
        <div className="nm-hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen ? <X size={24} /> : <Menu size={24} />}
        </div>
      </nav>
      <div className={`nm-mobile${menuOpen ? ' open' : ''}`}>
        {navItems.map(({ name, path, icon: Icon }) => (
          <Link key={path} to={path}
            className={`nm-link${location.pathname === path ? ' active' : ''}`}
            onClick={() => setMenuOpen(false)}>
            <Icon /> {name}
          </Link>
        ))}
        <button className="nm-logout" style={{ marginLeft: 0, marginTop: '8px' }}
          onClick={() => { handleLogout(); setMenuOpen(false); }}>
          <LogOut size={14} /> Logout
        </button>
      </div>
    </>
  );
};

export default Navbar;
